<template><view class="page"><view class="tabs"><view v-for="s in statuses" :key="s.value" :class="{on:status===s.value}" @click="setStatus(s.value)">{{s.label}}</view></view><view class="card" v-for="o in orders" :key="o.id" @click="go(o.id)"><text class="title">订单 {{o.orderNo||o.id}}</text><text class="muted">{{o.statusText||o.status}}</text><text class="price">¥{{o.payAmount}}</text></view><view v-if="!orders.length" class="card muted">暂无订单</view></view></template><script setup lang="ts">import { ref } from 'vue';import { onLoad,onShow } from '@dcloudio/uni-app';import { orderApi } from '@/services/order';import { listOf } from '@/utils/format';const status=ref(''),orders=ref<any[]>([]);const statuses=[{label:'全部',value:''},{label:'待付款',value:'pending'},{label:'待发货',value:'paid'},{label:'已发货',value:'shipped'},{label:'已完成',value:'completed'},{label:'已取消',value:'cancelled'},{label:'售后中',value:'aftersale'}];async function load(){orders.value=listOf((await orderApi.list({status:status.value})).data)}function setStatus(v:string){status.value=v;load()}function go(id:any){uni.navigateTo({url:'/pages/order/detail/index?id='+id})}onLoad((o:any)=>status.value=o.status||'');onShow(load)</script><style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c}.tabs{display:flex;overflow:auto;gap:12rpx;padding:20rpx}.tabs view{white-space:nowrap;background:#fff;padding:16rpx 22rpx;border-radius:999rpx}.tabs .on{background:#2b1207;color:#f0bf55}.card{background:#fff;margin:20rpx;padding:28rpx;border-radius:16rpx}.title{display:block;font-size:34rpx;font-weight:900}.muted{display:block;color:#8d8175;font-size:24rpx;margin-top:12rpx}.price{display:block;color:#b97700;font-weight:900;margin-top:12rpx}</style>
